// frontend/src/App.jsx — Shared router (Member 1 sets this up)
// Simple page router — no react-router needed

import { useState } from "react";
import Login from "./pages/Login";
import Dashboard from "./pages/Dashboard";
import Campaign from "./pages/Campaign";
import Refund from "./pages/Refund";
import History from "./pages/History";
 
export default function App() {
  const [user, setUser]                         = useState(null);
  const [page, setPage]                         = useState("dashboard");
  const [selectedCampaign, setSelectedCampaign] = useState(null);
 
  function handleLogin(userData) {
    setUser(userData);
    setPage("dashboard");
  }
 
  function handleSelectCampaign(campaign) {
    setSelectedCampaign(campaign);
    setPage("campaign");
  }
 
  if (!user) return <Login onLogin={handleLogin} />;
 
  return (
    <div style={{ minHeight: "100vh", background: "#0A0A0C", fontFamily: "'Inter', -apple-system, sans-serif" }}>
 
      {/* ── Nav Bar ── */}
      <nav style={{
        background: "#0D0D0F",
        borderBottom: "1px solid #1A1A1D",
        padding: "0 28px",
        display: "flex",
        alignItems: "center",
        height: 52,
        position: "sticky",
        top: 0,
        zIndex: 100,
      }}>
        {/* Logo */}
        <span style={{
          fontWeight: 700, color: "#fff", fontSize: 16,
          letterSpacing: "-0.4px", marginRight: 32,
        }}>
          ◈ CrowdChain
        </span>
 
        {/* Nav Links */}
        <div style={{ display: "flex", gap: 4, flex: 1 }}>
          {[
            { label: "Campaigns", key: "dashboard" },
            { label: "Refunds",   key: "refund"    },
            { label: "History",   key: "history"   },
          ].map(item => (
            <button key={item.key} onClick={() => setPage(item.key)} style={{
              background: page === item.key ? "#1C1C1F" : "none",
              border: page === item.key ? "1px solid #2C2C2E" : "1px solid transparent",
              borderRadius: 7,
              padding: "5px 12px",
              cursor: "pointer",
              color: page === item.key ? "#fff" : "#636366",
              fontWeight: page === item.key ? 500 : 400,
              fontSize: 13,
              fontFamily: "inherit",
              transition: "all 0.15s",
            }}>
              {item.label}
            </button>
          ))}
        </div>
 
        {/* User Info */}
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <div style={{
            width: 26, height: 26, borderRadius: "50%",
            background: "#7C71F220", border: "1px solid #7C71F240",
            display: "flex", alignItems: "center", justifyContent: "center",
            fontSize: 11, color: "#7C71F2", fontWeight: 600,
          }}>
            {user.username?.charAt(0).toUpperCase()}
          </div>
          <span style={{ fontSize: 13, color: "#636366" }}>
            {user.username}
          </span>
          <span style={{ fontSize: 11, color: "#2C2C2E", fontFamily: "monospace" }}>
            {user.address?.slice(0,6)}...{user.address?.slice(-4)}
          </span>
          <button onClick={() => setUser(null)} style={{
            background: "none", border: "1px solid #2C2C2E",
            borderRadius: 6, padding: "4px 10px",
            color: "#636366", fontSize: 12, cursor: "pointer",
            fontFamily: "inherit", marginLeft: 4,
            transition: "all 0.15s",
          }}>
            Logout
          </button>
        </div>
      </nav>
 
      {/* ── Pages ── */}
      <main>
        {page === "dashboard" && (
          <Dashboard user={user} onSelectCampaign={handleSelectCampaign} />
        )}
        {page === "campaign" && selectedCampaign && (
          <Campaign campaign={selectedCampaign} user={user} onBack={() => setPage("dashboard")} />
        )}
        {page === "refund"   && <Refund  user={user} />}
        {page === "history"  && <History user={user} />}
      </main>
    </div>
  );
}
